import{_ as e,a,b as o,c as r,d}from"./chunks/复制刷新令牌.IwW3dosg.js";import{_ as i,o as n,c as s,a2 as l}from"./chunks/framework.DnrXFDHb.js";const v=JSON.parse('{"title":"Добавление канала OneDrive","description":"","frontmatter":{},"headers":[],"relativePath":"ru-RU/upload/onedrive.md","filePath":"ru-RU/upload/onedrive.md","lastUpdated":1781962217000}'),c={name:"ru-RU/upload/onedrive.md"};function p(h,t,m,u,b,f){return n(),s("div",null,[...t[0]||(t[0]=[l('<h1 id="добавление-канала-onedrive" tabindex="-1">Добавление канала OneDrive <a class="header-anchor" href="#добавление-канала-onedrive" aria-label="Permalink to &quot;Добавление канала OneDrive&quot;">​</a></h1><h2 id="что-подготовить-сначала" tabindex="-1">Что подготовить сначала <a class="header-anchor" href="#что-подготовить-сначала" aria-label="Permalink to &quot;Что подготовить сначала&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Что нужно</th><th>Зачем это нужно</th></tr></thead><tbody><tr><td>Аккаунт Microsoft</td><td>Для доступа к страницам администрирования Microsoft и авторизации OneDrive</td></tr><tr><td>Ваш домен ImgBed</td><td>Для OAuth callback URL</td></tr><tr><td>App registration</td><td>Для получения <code>Client ID</code> и <code>Client Secret</code></td></tr><tr><td>Аккаунт OneDrive</td><td>Фактическое место хранения файлов</td></tr></tbody></table><h2 id="настроика" tabindex="-1">Настройка <a class="header-anchor" href="#настроика" aria-label="Permalink to &quot;Настройка&quot;">​</a></h2><h3 id="шаг-1-откроите-microsoft-entra-id" tabindex="-1">Шаг 1. Откройте Microsoft Entra ID <a class="header-anchor" href="#шаг-1-откроите-microsoft-entra-id" aria-label="Permalink to &quot;Шаг 1. Откройте Microsoft Entra ID&quot;">​</a></h3><ol><li>Откройте <code>portal.azure.com</code>.</li><li>Вверху найдите <code>Microsoft Entra ID</code>.</li><li>Если нужная страница не появилась в выпадающем списке, выберите:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Continue searching in Microsoft Entra ID</span></span></code></pre></div><ol start="4"><li>Откройте <code>Microsoft Entra ID</code>.</li><li>Откройте <code>App registrations</code>.</li><li>Нажмите <code>New registration</code>.</li></ol><h3 id="шаг-2-зарегистрируите-приложение" tabindex="-1">Шаг 2. Зарегистрируйте приложение <a class="header-anchor" href="#шаг-2-зарегистрируите-приложение" aria-label="Permalink to &quot;Шаг 2. Зарегистрируйте приложение&quot;">​</a></h3><p>На странице <code>New registration</code> заполните:</p><table tabindex="0"><thead><tr><th>Поле</th><th>Что ввести</th></tr></thead><tbody><tr><td>Name</td><td>Понятное имя, например <code>imgbed-onedrive</code></td></tr><tr><td>Supported account types</td><td>Выберите по таблице ниже</td></tr><tr><td>Redirect URI type</td><td><code>Web</code></td></tr><tr><td>Redirect URI</td><td><code>https://your-domain.com/api/oauth/onedrive/callback</code></td></tr></tbody></table><p>Подсказка по типу аккаунтов:</p><table tabindex="0"><thead><tr><th>Ваш сценарий</th><th>Supported Account Types</th></tr></thead><tbody><tr><td>Только личный OneDrive</td><td>Выберите вариант для personal Microsoft account.</td></tr><tr><td>Личные и рабочие или учебные аккаунты</td><td>Выберите вариант, поддерживающий personal и organizational accounts.</td></tr><tr><td>Только корпоративный или учебный OneDrive</td><td>Выберите вариант для organizational account.</td></tr></tbody></table><p>После заполнения формы нажмите register.</p><p><img src="'+e+'" alt="Создание OneDrive app" loading="lazy"></p><h3 id="шаг-3-скопируите-данные-приложения" tabindex="-1">Шаг 3. Скопируйте данные приложения <a class="header-anchor" href="#шаг-3-скопируите-данные-приложения" aria-label="Permalink to &quot;Шаг 3. Скопируйте данные приложения&quot;">​</a></h3><p>После создания приложения скопируйте значения со страницы overview:</p><table tabindex="0"><thead><tr><th>Поле Microsoft</th><th>Поле ImgBed</th></tr></thead><tbody><tr><td><code>Application (client) ID</code></td><td><code>Client ID</code></td></tr><tr><td><code>Directory (tenant) ID</code></td><td><code>Tenant ID</code> для organizational accounts</td></tr></tbody></table><p><img src="'+a+'" alt="Application и tenant IDs" loading="lazy"></p><h3 id="шаг-4-создаите-client-secret" tabindex="-1">Шаг 4. Создайте Client Secret <a class="header-anchor" href="#шаг-4-создаите-client-secret" aria-label="Permalink to &quot;Шаг 4. Создайте Client Secret&quot;">​</a></h3><ol><li>Откройте <code>Certificates &amp; secrets</code>.</li><li>Нажмите <code>New client secret</code>.</li><li>Введите удобное описание.</li><li>Выберите срок действия.</li><li>Сразу после создания скопируйте <code>Value</code>.</li></ol><p><img src="'+o+'" alt="Сохранение значения client secret" loading="lazy"></p><h3 id="шаг-5-добавьте-api-permissions" tabindex="-1">Шаг 5. Добавьте API permissions <a class="header-anchor" href="#шаг-5-добавьте-api-permissions" aria-label="Permalink to &quot;Шаг 5. Добавьте API permissions&quot;">​</a></h3><ol><li>Откройте <code>API permissions</code>.</li><li>Нажмите <code>Add a permission</code>.</li><li>Выберите <code>Microsoft Graph</code>.</li><li>Выберите <code>Delegated permissions</code>.</li><li>Добавьте:</li></ol><table tabindex="0"><thead><tr><th>Permission</th><th>Назначение</th></tr></thead><tbody><tr><td><code>Files.ReadWrite.All</code></td><td>Загрузка файлов, создание папок и удаление файлов</td></tr><tr><td><code>offline_access</code></td><td>Позволяет ImgBed получить <code>Refresh Token</code></td></tr><tr><td><code>User.Read</code></td><td>Читает информацию об аккаунте и квоте</td></tr></tbody></table><h3 id="шаг-6-заполните-канал-onedrive" tabindex="-1">Шаг 6. Заполните канал OneDrive <a class="header-anchor" href="#шаг-6-заполните-канал-onedrive" aria-label="Permalink to &quot;Шаг 6. Заполните канал OneDrive&quot;">​</a></h3><p>В настройках загрузки выберите <code>OneDrive</code> и заполните:</p><table tabindex="0"><thead><tr><th>Поле ImgBed</th><th>Что ввести</th></tr></thead><tbody><tr><td>Channel name</td><td>Понятное имя, например <code>Main OneDrive</code></td></tr><tr><td>Client ID</td><td>Microsoft <code>Application (client) ID</code></td></tr><tr><td>Client Secret</td><td>Скопированное значение <code>Client Secret Value</code></td></tr><tr><td>Tenant ID</td><td>Выберите по таблице ниже</td></tr><tr><td>Refresh Token</td><td>Пока оставьте пустым</td></tr><tr><td>Root directory</td><td>Необязательно. По умолчанию <code>imgbed</code>.</td></tr><tr><td>Note</td><td>Необязательно</td></tr></tbody></table><p><img src="'+r+'" alt="Заполнение конфигурации OneDrive-канала" loading="lazy"></p><p>Как заполнить <code>Tenant ID</code>:</p><table tabindex="0"><thead><tr><th>Выбранный тип аккаунтов</th><th>ImgBed <code>Tenant ID</code></th></tr></thead><tbody><tr><td>Personal accounts</td><td><code>consumers</code></td></tr><tr><td>Personal + organizational accounts</td><td><code>common</code></td></tr><tr><td>Только текущая организация</td><td><code>Directory (tenant) ID</code></td></tr></tbody></table><h3 id="шаг-7-получите-refresh-token" tabindex="-1">Шаг 7. Получите Refresh Token <a class="header-anchor" href="#шаг-7-получите-refresh-token" aria-label="Permalink to &quot;Шаг 7. Получите Refresh Token&quot;">​</a></h3><ol><li>В ImgBed нажмите <code>Get Token</code>.</li><li>Войдите в Microsoft-аккаунт, который хотите подключить.</li><li>Подтвердите запрос авторизации.</li><li>На callback-странице появится <code>Refresh Token</code>.</li><li>Скопируйте его.</li><li>Вернитесь в ImgBed и вставьте его в поле <code>Refresh Token</code>.</li></ol><p><img src="'+d+`" alt="Копирование refresh token" loading="lazy"></p><h3 id="шаг-8-сохраните-канал" tabindex="-1">Шаг 8. Сохраните канал <a class="header-anchor" href="#шаг-8-сохраните-канал" aria-label="Permalink to &quot;Шаг 8. Сохраните канал&quot;">​</a></h3><p>Когда все поля заполнены, сохраните канал.</p><h2 id="короткии-сценарии" tabindex="-1">Короткий сценарий <a class="header-anchor" href="#короткии-сценарии" aria-label="Permalink to &quot;Короткий сценарий&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Открыть portal.azure.com</span></span>
<span class="line"><span>-&gt; Найти Microsoft Entra ID</span></span>
<span class="line"><span>-&gt; Открыть App registrations</span></span>
<span class="line"><span>-&gt; Зарегистрировать новое app</span></span>
<span class="line"><span>-&gt; Заполнить Name / Supported account types / Web redirect URI</span></span>
<span class="line"><span>-&gt; Зарегистрировать</span></span>
<span class="line"><span>-&gt; Скопировать Application (client) ID</span></span>
<span class="line"><span>-&gt; Проверить callback URL в Authentication</span></span>
<span class="line"><span>-&gt; Создать Client Secret в Certificates &amp; secrets</span></span>
<span class="line"><span>-&gt; Добавить permissions в API permissions</span></span>
<span class="line"><span>-&gt; Ввести Client ID / Client Secret / Tenant ID в ImgBed</span></span>
<span class="line"><span>-&gt; Нажать Get Token</span></span>
<span class="line"><span>-&gt; Скопировать Refresh Token с callback-страницы</span></span>
<span class="line"><span>-&gt; Вставить его обратно в ImgBed и сохранить</span></span></code></pre></div><h2 id="ссылки" tabindex="-1">Ссылки <a class="header-anchor" href="#ссылки" aria-label="Permalink to &quot;Ссылки&quot;">​</a></h2><ol><li>Microsoft Entra app registration: <a href="https://learn.microsoft.com/en-us/entra/identity-platform/quickstart-register-app" target="_blank" rel="noreferrer">https://learn.microsoft.com/en-us/entra/identity-platform/quickstart-register-app</a></li><li>Microsoft identity platform authorization code flow: <a href="https://learn.microsoft.com/en-us/entra/identity-platform/v2-oauth2-auth-code-flow" target="_blank" rel="noreferrer">https://learn.microsoft.com/en-us/entra/identity-platform/v2-oauth2-auth-code-flow</a></li><li>Microsoft Graph user authentication: <a href="https://learn.microsoft.com/en-us/graph/auth-v2-user" target="_blank" rel="noreferrer">https://learn.microsoft.com/en-us/graph/auth-v2-user</a></li></ol>`,40)])])}const D=i(c,[["render",p]]);export{v as __pageData,D as default};
